# Category: cicd_security

pipeline {
    agent any

    environment {
        DEPLOY_USER = 'deploy'
        DEPLOY_HOSTS = 'prod1.example.com prod2.example.com'
        DEPLOY_PATH = '/opt/myapp'
        ARTIFACT = 'build/myapp.tar.gz'
    }

    stages {
        stage('Validate Configuration') {
            steps {
                script {
                    if (!env.DEPLOY_HOSTS?.trim()) {
                        error('DEPLOY_HOSTS is required')
                    }
                    if (!fileExists(env.ARTIFACT)) {
                        error("Artifact not found: ${env.ARTIFACT}")
                    }
                }
            }
        }

        stage('Deploy to Production') {
            steps {
                withCredentials([usernamePassword(credentialsId: 'prod-ssh-credentials', usernameVariable: 'SSH_USER', passwordVariable: 'SSH_PASS')]) {
                    script {
                        def hosts = env.DEPLOY_HOSTS.split(/\s+/).findAll { it?.trim() }
                        for (host in hosts) {
                            sh """
                                set +x
                                export SSHPASS="\$SSH_PASS"
                                sshpass -e scp -o StrictHostKeyChecking=no "${env.ARTIFACT}" "\$SSH_USER@${host}:/tmp/myapp.tar.gz"
                                sshpass -e ssh -o StrictHostKeyChecking=no "\$SSH_USER@${host}" '
                                    set -e
                                    sudo mkdir -p ${env.DEPLOY_PATH}
                                    sudo tar -xzf /tmp/myapp.tar.gz -C ${env.DEPLOY_PATH}
                                    rm -f /tmp/myapp.tar.gz
                                    sudo systemctl restart myapp
                                    sudo systemctl status myapp --no-pager
                                '
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        success {
